// constants
const steps = [
  {
    id: "01",
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: "02",
    title: "Digital Wireframe",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: "03",
    title: "Clickable Prototype",
    description: "Better a diamond with a flaw than a pebble without one."
  }
];

//  ------------------------------ | PROCESS 3 | ------------------------------  //

export default function Process3() {
  return (
    <section className="py-20">
      <div className="mx-auto container px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14 flex flex-col gap-3 max-w-sm mx-auto">
          <h2 className="text-foreground">
            Our Process Is Aimed To Help Your Business
          </h2>
          <p className="text-muted-foreground">
            Only those who risk going too far can possibly find out how far one
            can go.
          </p>
        </div>

        {/* Steps grid */}
        <div className="grid grid-cols-12 gap-8">
          {steps.map((step) => (
            <div
              key={step.id}
              className="col-span-12 sm:col-span-4 flex flex-col gap-3"
            >
              <span className="text-6xl font-bold text-primary">{step.id}</span>
              <h5 className="text-foreground font-bold">{step.title}</h5>
              <p className="text-muted-foreground text-md">
                {step.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
